const KEY = 'monopoly_deal_autofollow';
const params = new URLSearchParams(window.location.search);
const current = params.get('var-game') || '';
const auto = localStorage.getItem(KEY) !== 'false';
const go = (g) => { const u = new URL(window.location.href); u.searchParams.set('var-game', g); window.location.assign(u.toString()); };
const shortId = (id) => id && id.length > 18 ? id.slice(0, 8) + '...' + id.slice(-4) : id;
return fetch('http://localhost:9104/games').then(r => r.json()).then(games => {
  const latest = Array.isArray(games) && games.length ? games[games.length - 1] : '';
  if (auto && latest && latest !== current) { setTimeout(() => go(latest), 100); }
  const statusText = !latest ? 'no games yet' : (latest === current ? 'on latest - ' + shortId(latest) : 'latest: ' + shortId(latest) + '   current: ' + shortId(current));
  return {
    backgroundColor: 'transparent',
    graphic: [
      { type: 'group', left: 16, top: 'middle', children: [
        { type: 'rect', shape: { width: 140, height: 28, r: 6 }, style: { fill: '#8f6b2d', stroke: '#dfc388', lineWidth: 1 }, cursor: 'pointer', onclick: () => { if (latest) go(latest); } },
        { type: 'text', left: 70, top: 14, style: { text: 'Go to latest', fill: '#ffffff', font: '13px system-ui', textAlign: 'center', textVerticalAlign: 'middle' }, silent: true }
      ] },
      { type: 'group', left: 180, top: 'middle', children: [
        { type: 'rect', shape: { width: 220, height: 28, r: 6 }, style: { fill: auto ? '#2d6a4a' : '#333a44', stroke: '#888', lineWidth: 1 }, cursor: 'pointer', onclick: () => { localStorage.setItem(KEY, auto ? 'false' : 'true'); window.location.reload(); } },
        { type: 'text', left: 110, top: 14, style: { text: (auto ? '[x]' : '[ ]') + '  Auto-follow latest', fill: '#ffffff', font: '13px system-ui', textAlign: 'center', textVerticalAlign: 'middle' }, silent: true }
      ] },
      { type: 'text', left: 450, top: 'middle', style: { text: statusText, fill: latest && latest === current ? '#9ecc8f' : '#e6e8ea', font: '13px ui-monospace, monospace', textVerticalAlign: 'middle' }, silent: true }
    ]
  };
}).catch(e => ({ graphic: [{ type: 'text', left: 16, top: 'middle', style: { text: 'probe failed: ' + e.message, fill: '#ff9090' }, silent: true }] }));

const COLOR = ['#d9485f', '#57a0d8', '#d9b45b', '#6fbf73', '#c77dff'];
const game = new URLSearchParams(window.location.search).get('var-game') || '';
