    series: players.map((p, i) => ({ name: p, type: 'line', step: 'end', showSymbol: false, itemStyle: { color: COLOR[i] || '#888' }, lineStyle: { width: 2, color: COLOR[i] || '#888' }, areaStyle: { color: COLOR[i] || '#888', opacity: 0.06 }, data: snaps.map(s => [s.seq, metric(s, p, 'completedSets')]) }))
