const game = new URLSearchParams(window.location.search).get('var-game') || '';
return fetch('http://localhost:9104/history?game=' + encodeURIComponent(game)).then(r => r.json()).then(h => {
  const events = h.events || [];
  const types = [...new Set(events.map(e => e.type))].sort();
  const counts = Object.fromEntries(types.map(t => [t, 0]));
  const rows = events.map(e => { counts[e.type]++; return { seq: e.seq, snapshot: { ...counts } }; });
  return {
    backgroundColor: 'transparent', tooltip: { trigger: 'axis' }, legend: { data: types, textStyle: { color: '#e6e8ea' }, top: 4, type: 'scroll' },
    grid: { top: 50, left: 40, right: 20, bottom: 28 },
    xAxis: { type: 'value', name: 'seq', nameTextStyle: { color: '#e6e8ea' }, axisLabel: { color: '#e6e8ea' }, axisLine: { lineStyle: { color: '#555' } }, splitLine: { lineStyle: { color: 'rgba(255,255,255,0.08)' } } },
